const express = require('express');
const axios = require('axios');
const crypto = require('crypto');
const rateLimit = require('express-rate-limit');
const helmet = require('helmet');

const app = express();

app.use(helmet());
app.use(express.json());

const VALID_API_KEYS = new Map();
const API_KEY_HASH_SALT = process.env.API_KEY_SALT || crypto.randomBytes(32).toString('hex');

function hashApiKey(apiKey) {
  return crypto.createHmac('sha256', API_KEY_HASH_SALT).update(apiKey).digest('hex');
}

function addApiKey(apiKey) {
  const hashedKey = hashApiKey(apiKey);
  VALID_API_KEYS.set(hashedKey, {
    createdAt: new Date(),
    lastUsed: new Date()
  });
}

addApiKey('demo-key-12345');
addApiKey('test-key-67890');

const BACKEND_SERVICES = {
  'users': process.env.USERS_SERVICE_URL || 'http://localhost:3001',
  'orders': process.env.ORDERS_SERVICE_URL || 'http://localhost:3002',
  'products': process.env.PRODUCTS_SERVICE_URL || 'http://localhost:3003'
};

const limiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100,
  standardHeaders: true,
  legacyHeaders: false,
  handler: (req, res) => {
    logRequest(req, 'RATE_LIMIT_EXCEEDED', null);
    res.status(429).json({ error: 'Too many requests' });
  }
});

app.use(limiter);

function logRequest(req, status, apiKeyHash) {
  const logEntry = {
    timestamp: new Date().toISOString(),
    method: req.method,
    path: req.path,
    ip: req.ip,
    userAgent: req.get('user-agent'),
    status: status,
    apiKeyHash: apiKeyHash,
    service: req.params.service
  };
  
  console.log(JSON.stringify(logEntry));
}

function validateApiKey(apiKey) {
  if (!apiKey || typeof apiKey !== 'string') {
    return false;
  }
  
  if (apiKey.length < 10 || apiKey.length > 128) {
    return false;
  }
  
  const hashedKey = hashApiKey(apiKey);
  const keyData = VALID_API_KEYS.get(hashedKey);
  
  if (keyData) {
    keyData.lastUsed = new Date();
    return hashedKey;
  }
  
  return false;
}

function apiKeyAuth(req, res, next) {
  const apiKey = req.query.api_key;
  
  const hashedKey = validateApiKey(apiKey);
  
  if (!hashedKey) {
    logRequest(req, 'UNAUTHORIZED', null);
    return res.status(401).json({ error: 'Invalid or missing API key' });
  }
  
  req.apiKeyHash = hashedKey;
  
  delete req.query.api_key;
  
  next();
}

app.use('/api/:service/*', apiKeyAuth);

app.all('/api/:service/*', async (req, res) => {
  const serviceName = req.params.service;
  const serviceUrl = BACKEND_SERVICES[serviceName];
  
  if (!serviceUrl) {
    logRequest(req, 'SERVICE_NOT_FOUND', req.apiKeyHash);
    return res.status(404).json({ error: 'Service not found' });
  }
  
  const path = req.params[0];
  const targetUrl = `${serviceUrl}/${path}`;
  
  try {
    const headers = {
      'X-API-Key': req.apiKeyHash,
      'X-Forwarded-For': req.ip,
      'X-Original-Host': req.hostname,
      'Content-Type': req.get('content-type') || 'application/json'
    };
    
    const config = {
      method: req.method,
      url: targetUrl,
      headers: headers,
      params: req.query,
      timeout: 30000,
      maxRedirects: 0,
      validateStatus: () => true
    };
    
    if (['POST', 'PUT', 'PATCH'].includes(req.method)) {
      config.data = req.body;
    }
    
    const response = await axios(config);
    
    logRequest(req, response.status, req.apiKeyHash);
    
    res.status(response.status).json(response.data);
    
  } catch (error) {
    logRequest(req, 'ERROR', req.apiKeyHash);
    
    if (error.code === 'ECONNREFUSED') {
      return res.status(503).json({ error: 'Service unavailable' });
    }
    
    if (error.code === 'ETIMEDOUT') {
      return res.status(504).json({ error: 'Gateway timeout' });
    }
    
    res.status(500).json({ error: 'Internal server error' });
  }
});

app.get('/health', (req, res) => {
  res.json({ status: 'healthy', timestamp: new Date().toISOString() });
});

app.use((req, res) => {
  logRequest(req, 'NOT_FOUND', null);
  res.status(404).json({ error: 'Endpoint not found' });
});

app.use((err, req, res, next) => {
  console.error('Unhandled error:', err);
  logRequest(req, 'ERROR', req.apiKeyHash || null);
  res.status(500).json({ error: 'Internal server error' });
});

const PORT = process.env.PORT || 3000;

app.listen(PORT, () => {
  console.log(`API Gateway running on port ${PORT}`);
  console.log('Available services:', Object.keys(BACKEND_SERVICES));
});

module.exports = app;